class Solution {
public:
    bool canConstruct(string s, int k) {
        unordered_map<char, int> freq;
        for (char c : s) {
            freq[c]++;
        }

        int oddCount = 0;
        for (auto& pair : freq) {
            if (pair.second % 2 != 0) {
                oddCount++;
            }
        }

        return oddCount <= k && k <= s.length();
    }
};
